    ('cat_potty', 1, 1, 'visible', true, false, 'Best for comfortable, stable sitting', 'Potty Chair', 'BabyBjörn', 'Amazon UK', 'https://www.amazon.co.uk/BabyBj%C3%B6rn-Potty-Chair-White-Grey/dp/B00005842W', NULL, '£28.00', 'in_stock', '18m+', 'A sturdy potty chair with a high backrest, comfortable armrests, and a removable inner potty for easy cleaning.', 'This is a brilliant, stable choice for early practice. The high back offers great support for toddlers who need to sit for a while, and it''s incredibly easy to empty.', 'Provides the stability and comfort needed for a 28-30 month old who is just starting to practice sitting on a potty.', 'It is quite bulky, so it''s not ideal for small bathrooms or travel.', 'buy', false, 'This is a parent buy, not a default gift.', NULL, NULL, 'strong', ARRAY['https://www.mumsnet.com/swearsby/best-potties']::text[], 'none'),
