    ('cat_soft_graspable_balls', 1, 1, 'visible', true, false, 'Best for first kicks and barefoot play', 'Mini Football Sunny 300 Size 1 - Pastel Pink', 'KIPSTA', 'Decathlon', 'https://www.decathlon.co.uk/p/mini-football-sunny-300-size-1-pastel-pink/146095/c174c344c227m8753526', NULL, '£2.99', 'in_stock', 'Size 1', 'A lightweight, soft foam football in pastel pink, perfect for indoor and outdoor play, encouraging early football skills.', 'This ball is brilliant for toddlers getting confident with their feet. Its soft, lightweight design means it''s safe for indoor adventures and gentle on little toes for outdoor kicking. It’s about giving movement a job, encouraging solo exploration of kicking and chasing, rather than structured games. Skip if your child prefers heavier, more traditional footballs.', 'Perfectly sized and soft enough for a 28-30 month old to practice kicking without frustration or injury.', 'Foam may degrade over time with heavy outdoor use.', 'buy', true, 'A simple gift that works indoors or outdoors.', 'If the family has balls already, this is about giving movement a job, not adding duplicates.', NULL, 'strong', ARRAY['https://www.decathlon.co.uk/p/mini-football-sunny-300-size-1-pastel-pink/146095/c174c344c227m8753526']::text[], 'none'),
    ('cat_soft_graspable_balls', 2, 2, 'visible', true, true, 'Best for durable outdoor kicking practice', 'Garden Football - Size 1 (Mini)', 'FORZA', 'FORZA', 'https://www.forza.com/uk/forza-recreational-garden-football+forza_match_football_size-Size~1~Mini+pack_size-Pack~of~1', NULL, '£3.60', 'in_stock', 'Size 1', 'A soft, lightweight, and durable size 1 football designed for casual kickabouts in the garden, perfect for toddlers.', 'This FORZA football is a fantastic choice for toddlers who are ready for more robust outdoor kicking. Its durability means it can withstand enthusiastic play, while its soft nature keeps it safe. It supports the development of solo movement confidence, allowing your child to practice kicking and chasing without the pressure of team play. Hold off if you primarily need an indoor-only ball.', 'Durable enough for outdoor use while remaining soft enough for a toddler''s developing kick.', 'Might be slightly heavier than pure foam options.', 'buy', true, 'A simple gift that works indoors or outdoors.', 'If the family has balls already, this is about giving movement a job, not adding duplicates.', NULL, 'good', ARRAY['https://www.forza.com/uk/forza-recreational-garden-football+forza_match_football_size-Size~1~Mini+pack_size-Pack~of~1']::text[], 'none'),
    ('cat_soft_graspable_balls', 3, 3, 'visible', true, true, 'Best for varied sports exploration', '5-inch Soccer Ball (from Pack of 4 Toddler Balls)', 'INPODAK', 'Amazon UK', 'https://www.amazon.co.uk/INPODAK-Toddlers-Football-Basketball-Backyard/dp/B0BX24P61T', NULL, '£17.99', 'in_stock', '6 months - 5 years', 'A soft, small 5-inch soccer ball, part of a multi-sport set, ideal for toddlers to kick and handle indoors or out.', 'This soccer ball, from a popular INPODAK set, is perfectly sized for 28-30 month olds to develop their kicking and chasing skills. Its soft material and small size make it easy for little feet to connect with, fostering that crucial solo movement confidence. The multi-ball set offers variety, but the soccer ball specifically targets the objective. Borrow if you already have other small balls, otherwise buy for the versatility.', 'Small size and soft material are ideal for early kicking practice.', 'Comes as part of a set, which might be more than needed.', 'buy', true, 'A simple gift that works indoors or outdoors.', 'If the family has balls already, this is about giving movement a job, not adding duplicates.', NULL, 'strong', ARRAY['https://www.amazon.co.uk/INPODAK-Toddlers-Football-Basketball-Backyard/dp/B0BX24P61T']::text[], 'check_url'),
    ('cat_soft_graspable_balls', 4, 4, 'visible', true, true, 'Best for developing ball control', 'Foam Football', 'Sports Directory', 'Sports Direct', 'https://www.sportsdirect.com/sports-directory-foam-football-857872', NULL, '£6.00', 'in_stock', 'Not specified', 'A 20cm lightweight foam football, perfect for indoor and outdoor play, designed to help toddlers develop accuracy and control.', 'This foam football is an excellent tool for refining a toddler''s kicking and chasing abilities. Its lightweight nature and 20cm diameter make it manageable for little ones, promoting better control and accuracy as they experiment with movement. It''s soft enough for indoor use, making it a versatile option for year-round active play. Bring back out if you have a similar foam ball, otherwise buy.', 'The 20cm size is a good target for toddlers learning to kick with more purpose.', 'Foam can be picked at or bitten by some toddlers.', 'buy', true, 'A simple gift that works indoors or outdoors.', 'If the family has balls already, this is about giving movement a job, not adding duplicates.', NULL, 'good', ARRAY['https://www.sportsdirect.com/sports-directory-foam-football-857872']::text[], 'none'),
    ('cat_soft_graspable_balls', 5, 5, 'visible', true, true, 'Best for gentle indoor/outdoor play', 'Soft Foam Football Blue - 20 cm', 'Twisk', 'Planet Happy Toys', 'https://www.planethappytoys.co.uk/product/13319/twisk-soft-foam-football-blue-20-cm-kids-play-ball.html', NULL, '£5.94', 'in_stock', '3 years+', 'A sturdy yet lightweight 20cm soft foam football in blue, safe for little feet and hands, ideal for indoor and outdoor play.', 'The Twisk soft foam football is a great option for toddlers who are gaining confidence in kicking and chasing. Its soft, lightweight foam construction ensures safety during play, both indoors and out. While the listing states 3 years+, its characteristics make it suitable for a 28-30 month old who is already walking confidently and ready for active ball play, focusing on solo movement. Hold off if your child is particularly rough with toys, as foam can be less durable than rubber.', 'Soft foam construction is safe for indoor kicking practice.', 'Age mark is 3+, likely due to foam material which could be bitten off.', 'buy', true, 'A simple gift that works indoors or outdoors.', 'If the family has balls already, this is about giving movement a job, not adding duplicates.', 'Supervise to ensure child does not bite or pick off pieces of foam.', 'good', ARRAY['https://www.planethappytoys.co.uk/product/13319/twisk-soft-foam-football-blue-20-cm-kids-play-ball.html']::text[], 'check_age_fit'),
    ('cat_soft_graspable_balls', 6, 6, 'visible', true, true, 'Best for budgets', 'Soft Football (125mm)', 'Gompels', NULL, 'https://www.gompels.co.uk/soft-football.html', NULL, '£5.00', NULL, NULL, 'Gompels — Soft Football (125mm)', 'Small, soft football ideal for infant/primary settings. Good for various activities, but might be a bit small for primary kicking and chasing focus for 28-30m.', 'Small, soft football ideal for infant/primary settings. Good for various activities, but might be a bit small for primary kicking and chasing focus for 28-30m.', NULL, 'borrow', NULL, NULL, NULL, NULL, 'emerging', ARRAY[]::text[], 'check_claim'),
    ('cat_soft_graspable_balls', 7, 7, 'visible', true, true, 'Best for small spaces', 'Soft Foam Football - 12cm', 'Live4Sport', NULL, 'https://www.live4sport.co.uk/product/soft-foam-football-12cm/', NULL, '£2.00', NULL, NULL, 'Live4Sport — Soft Foam Football - 12cm', 'Safe, lightweight 12cm ball. Promotes hand-eye coordination and balance, but similar to Gompels, potentially too small for primary kicking focus for 28-30m.', 'Safe, lightweight 12cm ball. Promotes hand-eye coordination and balance, but similar to Gompels, potentially too small for primary kicking focus for 28-30m.', NULL, 'borrow', NULL, NULL, NULL, NULL, 'emerging', ARRAY[]::text[], 'check_claim'),
    ('cat_soft_graspable_balls', 8, 8, 'visible', true, true, 'Best for borrowing first', 'Playground Balls for Toddlers 1-3 (2 Pack)', 'U&C Planet', NULL, 'https://www.u-buy.co.uk/product/DRU7VFY-kickball-playground-ball-8-5-inches-upgraded-rubber-bouncy-dodgeball-for-indoor-outdoor-ball-games-square-ball-for-kids-age-3-4-5-6-with-1-pump', NULL, '£15.00', NULL, NULL, 'U&C Planet — Playground Balls for Toddlers 1-3 (2 Pack)', 'Durable, non-toxic rubber balls, suitable for indoor/outdoor play. Good for toddlers aged 1 and above, but rubber might be harder than foam, and less ''soft'' for the category.', 'Durable, non-toxic rubber balls, suitable for indoor/outdoor play. Good for toddlers aged 1 and above, but rubber might be harder than foam, and less ''soft'' for the category.', NULL, 'borrow', NULL, NULL, NULL, NULL, 'emerging', ARRAY[]::text[], 'check_claim'),
    ('cat_soft_graspable_balls', 9, 9, 'visible', true, true, 'Best for gifting', 'Polka Dot Balls 20cm Pack of 4', 'First-Play', NULL, 'https://www.first-play.com/products/polka-dot-balls-20cm-pack-of-4', NULL, '£15.00', NULL, NULL, 'First-Play — Polka Dot Balls 20cm Pack of 4', 'Soft, 20cm balls, good for playdates and general ball play. Suitable for toddlers, but a pack of 4 might be more than needed for a single child.', 'Soft, 20cm balls, good for playdates and general ball play. Suitable for toddlers, but a pack of 4 might be more than needed for a single child.', NULL, 'borrow', NULL, NULL, NULL, NULL, 'emerging', ARRAY[]::text[], 'check_claim'),
    ('cat_soft_graspable_balls', 10, 10, 'visible', true, true, 'Best for growing with them', 'Soft Spikey Balls 4pk', 'TTS', NULL, 'https://www.tts-group.co.uk/primary/pe-sports/balls/sensory-balls/', NULL, '£11.99', NULL, NULL, 'TTS — Soft Spikey Balls 4pk', 'Sensory balls that can also be kicked and chased. Good for tactile stimulation and active play, but the primary focus is sensory, not pure kicking/chasing.', 'Sensory balls that can also be kicked and chased. Good for tactile stimulation and active play, but the primary focus is sensory, not pure kicking/chasing.', NULL, 'borrow', NULL, NULL, NULL, NULL, 'emerging', ARRAY[]::text[], 'check_claim'),
    ('cat_step_stool', 1, 1, 'visible', true, false, 'Best for child who insists on doing everything', 'Step Stool', 'BabyBjorn', NULL, 'https://www.babybjorn.co.uk/products/bathroom/step-stool/', 'https://a.storyblok.com/f/187315/1667x2500/2f2fa2de78/step-stool-deep-green-white-lookbook-04-pp-babybjorn.jpg/m/673.5x1010.0479904019196/smart/filters:quality(80)', '£24.90', 'in_stock', 'Not explicitly stated, but designed for toddlers learning independence.', 'A classic, stable, and non-slip step stool designed to help toddlers reach sinks and toilets, promoting independence.', 'This stool is excellent for 28-30 month olds due to its low height, exceptional stability, and full non-slip coverage. It''s easy for little ones to move themselves, fostering independence in daily routines like handwashing and teeth brushing. Its simple, sturdy design aligns perfectly with the independence-seeking phase. The low height (6 inches) is ideal for this age band, differentiating it from taller learning towers, which are more suitable for older toddlers.', 'This stool is excellent for 28-30 month olds due to its low height, exceptional stability, and full non-slip coverage. It''s easy for little ones to move themselves, fostering independence in daily routines like handwashing and teeth brushing. Its simple, sturdy design aligns perfectly with the independence-seeking phase. The low height (6 inches) is ideal for this age band, differentiating it from taller learning towers, which are more suitable for older toddlers.', NULL, 'buy', false, NULL, 'Supervise step use and keep away from hot, sharp or unstable surfaces.', 'Use a stable stool with supervision.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_step_stool', 2, 2, 'visible', true, true, 'Best for family seeking a reliable first step', 'FÖRSIKTIG children''s stool, white/turquoise', 'IKEA', NULL, 'https://www.ikea.com/gb/en/p/foersiktig-childrens-stool-white-turquoise-10591318/', 'https://www.ikea.com/gb/en/images/products/foersiktig-childrens-stool-white-turquoise__0727451_pe735777_s5.jpg', '£5.00', 'in_stock', 'Not explicitly stated, but reviews indicate suitability for toddlers.', 'A simple, stable, and very affordable children''s stool with anti-slip features, designed to help children reach sinks and toilets.', 'This stool is an excellent budget-friendly option for 28-30 month olds. Its wide, curved base and anti-slip features make it very stable, crucial for this age. The low height is perfect for promoting early independence without being too tall, aligning with the stage shift note of focusing on low, stable steps. It''s a practical choice for families seeking a no-frills, safe solution.', 'This stool is an excellent budget-friendly option for 28-30 month olds. Its wide, curved base and anti-slip features make it very stable, crucial for this age. The low height is perfect for promoting early independence without being too tall, aligning with the stage shift note of focusing on low, stable steps. It''s a practical choice for families seeking a no-frills, safe solution.', NULL, 'buy', false, NULL, 'Supervise step use and keep away from hot, sharp or unstable surfaces.', 'Use a stable stool with supervision.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_step_stool', 3, 3, 'visible', true, true, 'Best for child who needs a little extra', 'Step Stool', 'OXO Tot', NULL, 'https://www.amazon.co.uk/OXO-Tot-Step-Stool-White/dp/B0759QF6T2', 'https://m.media-amazon.com/images/I/51p0v7w-z8L._AC_SX679_.jpg', '£22.00', 'in_stock', 'Not explicitly stated, but designed for toddlers.', 'A sturdy and durable single-step stool with non-slip and anti-skid features, designed for toddlers to reach sinks and toilets.', 'The OXO Tot Step Stool is a solid choice for 28-30 month olds, offering a good balance of height, stability, and safety features. Its 7-inch height provides a slightly higher boost than the BabyBjorn or IKEA options, which can be beneficial as toddlers grow. The non-slip surface and anti-skid bottom ensure secure use, supporting the child''s growing independence in daily tasks. It''s a reliable, well-designed option that fits the criteria for this age band.', 'The OXO Tot Step Stool is a solid choice for 28-30 month olds, offering a good balance of height, stability, and safety features. Its 7-inch height provides a slightly higher boost than the BabyBjorn or IKEA options, which can be beneficial as toddlers grow. The non-slip surface and anti-skid bottom ensure secure use, supporting the child''s growing independence in daily tasks. It''s a reliable, well-designed option that fits the criteria for this age band.', NULL, 'buy', false, NULL, 'Supervise step use and keep away from hot, sharp or unstable surfaces.', 'Use a stable stool with supervision.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_step_stool', 4, 4, 'visible', true, true, 'Best for child mastering potty training.', 'Step Stool', 'Bumbo', NULL, 'https://www.amazon.co.uk/Bumbo-Step-Stool-Hemlock-Size/dp/B0877B7Q63', 'https://m.media-amazon.com/images/I/61t-Xw+s6GL._AC_SX679_.jpg', '£16.00', 'in_stock', 'Not explicitly stated, but suitable for toddlers.', 'A budget-friendly, stable, and lightweight single-step stool with a contour design that fits snugly against the toilet base.', 'This stool is an excellent option for 28-30 month olds, particularly for potty training due to its contour design. Its stability and good anti-skid properties are key for this age, providing a safe platform for developing independence. The lightweight nature allows toddlers to move it themselves, reinforcing their desire to do things themselves. Its low height is appropriate for the age band, focusing on simple, steady steps rather than taller learning towers.', 'This stool is an excellent option for 28-30 month olds, particularly for potty training due to its contour design. Its stability and good anti-skid properties are key for this age, providing a safe platform for developing independence. The lightweight nature allows toddlers to move it themselves, reinforcing their desire to do things themselves. Its low height is appropriate for the age band, focusing on simple, steady steps rather than taller learning towers.', NULL, 'buy', false, NULL, 'Supervise step use and keep away from hot, sharp or unstable surfaces.', 'Use a stable stool with supervision.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_step_stool', 5, 5, 'visible', true, true, 'Best for eco-conscious family.', 'Kids Step Stool', 'EKOBO', NULL, 'https://ekobo.co/products/bamboo-kids-step-stool-lemon', 'https://ekobo.co/cdn/shop/files/yellow_stool_92cedc4d-1ab3-4554-a92f-d0e624b5ddb6.jpg?v=1783939783&width=1000', '£34.00', 'in_stock', 'Not explicitly stated, but suitable for toddlers.', 'An eco-friendly, lightweight, and sturdy step stool with anti-slip texture, designed to help children reach sinks and counters.', 'The EKOBO Kids Step Stool is a great choice for 28-30 month olds, especially for families prioritizing eco-friendly materials. Its low height and anti-slip features provide the necessary stability and safety for this age group to practice independence in daily tasks. The lightweight design allows toddlers to easily move it, aligning with their desire to do things themselves. Its focus on low, stable steps makes it appropriate for the 28-30 month age band, distinguishing it from taller learning towers.', 'The EKOBO Kids Step Stool is a great choice for 28-30 month olds, especially for families prioritizing eco-friendly materials. Its low height and anti-slip features provide the necessary stability and safety for this age group to practice independence in daily tasks. The lightweight design allows toddlers to easily move it, aligning with their desire to do things themselves. Its focus on low, stable steps makes it appropriate for the 28-30 month age band, distinguishing it from taller learning towers.', NULL, 'buy', false, NULL, 'Supervise step use and keep away from hot, sharp or unstable surfaces.', 'Use a stable stool with supervision.', 'good', ARRAY[]::text[], 'none'),
    ('cat_step_stool', 6, 8, 'visible', true, true, 'Best for budgets', 'Single Step Stool', 'KEPLIN', NULL, NULL, NULL, '£14.00', NULL, NULL, 'KEPLIN — Single Step Stool', 'Decent stability, but not as aesthetically pleasing as other options.', 'Decent stability, but not as aesthetically pleasing as other options.', NULL, 'borrow', NULL, NULL, NULL, NULL, 'emerging', ARRAY[]::text[], 'check_url'),
    ('cat_step_stool', 7, 9, 'visible', true, true, 'Best for small spaces', 'Toddler Step Stool', 'HomlyPro', NULL, NULL, NULL, '£18.00', NULL, NULL, 'HomlyPro — Toddler Step Stool', 'Good non-slip features, but slightly heavier than ideal for toddler self-movement.', 'Good non-slip features, but slightly heavier than ideal for toddler self-movement.', NULL, 'borrow', NULL, NULL, NULL, NULL, 'emerging', ARRAY[]::text[], 'check_url'),
    ('cat_step_stool', 8, 11, 'visible', true, true, 'Best for borrowing first', 'Wooden Step Stool', 'Tidlo', NULL, NULL, NULL, '£25.00', NULL, NULL, 'Tidlo — Wooden Step Stool', 'Natural wood, but heavier and less portable for a toddler.', 'Natural wood, but heavier and less portable for a toddler.', NULL, 'borrow', NULL, NULL, NULL, NULL, 'emerging', ARRAY[]::text[], 'check_url'),
    ('cat_step_stool', 9, 12, 'visible', true, true, 'Best for gifting', 'Single Step Stool', 'Little Helper', NULL, NULL, NULL, '£20.00', NULL, NULL, 'Little Helper — Single Step Stool', 'Good quality, but higher price point for a basic single step.', 'Good quality, but higher price point for a basic single step.', NULL, 'borrow', NULL, NULL, NULL, NULL, 'emerging', ARRAY[]::text[], 'check_url'),
    ('cat_step_stool', 10, 13, 'visible', true, true, 'Best for growing with them', 'Toddler Step Stool', 'My Carry Potty', NULL, NULL, NULL, '£10.00', NULL, NULL, 'My Carry Potty — Toddler Step Stool', 'Integrated with potty training, but less versatile as a general step stool.', 'Integrated with potty training, but less versatile as a general step stool.', NULL, 'borrow', NULL, NULL, NULL, NULL, 'emerging', ARRAY[]::text[], 'check_url')
  ) AS v(source_category_entity_id, pick_rank, longlist_rank, status, is_visible, is_locked, best_for_tag, product_name, brand, retailer, product_url, image_url, price_text, stock_status, age_mark_on_listing, product_description, ember_verdict, why_it_fits, caveats, buy_borrow_hold_off, gift_suitable, gift_note, ownership_note, safety_notes, evidence_tier, evidence_sources, founder_qa_flag)
)
INSERT INTO public.pl_stage3_picks (
  age_band_id,
  category_type_id,
  source_category_entity_id,
  pick_rank,
  longlist_rank,
  status,
  is_visible,
  is_locked,
  best_for_tag,
  product_name,
  brand,
  retailer,
  product_url,
  image_url,
  price_text,
  stock_status,
  age_mark_on_listing,
  product_description,
  ember_verdict,
  why_it_fits,
  caveats,
  buy_borrow_hold_off,
  gift_suitable,
  gift_note,
  ownership_note,
  safety_notes,
  evidence_tier,
  evidence_sources,
  founder_qa_flag,
  research_payload
)
SELECT
  '28-30m',
  ct.id,
  r.source_category_entity_id,
  r.pick_rank,
  r.longlist_rank,
  r.status,
  r.is_visible,
  r.is_locked,
  r.best_for_tag,
  r.product_name,
  r.brand,
  r.retailer,
  r.product_url,
  r.image_url,
  r.price_text,
  r.stock_status,
  r.age_mark_on_listing,
  r.product_description,
  r.ember_verdict,
  r.why_it_fits,
  r.caveats,
  r.buy_borrow_hold_off,
  r.gift_suitable,
  r.gift_note,
  r.ownership_note,
  r.safety_notes,
  r.evidence_tier,
  r.evidence_sources,
  r.founder_qa_flag,
  jsonb_build_object(
    'bundle_schema_version', 'stage3_ingestion_bundle_v1',
    'bundle_generated_at', '2026-07-20T18:44:46.667Z',
    'research_schema_version', 'ember_picks_research_v2',
    'source_category_entity_id', r.source_category_entity_id
  )
FROM stage3_rows r
JOIN public.pl_category_types ct
  ON ct.slug = r.source_category_entity_id
WHERE EXISTS (
  SELECT 1
  FROM public.pl_age_band_development_need_category_types abdnct
  WHERE abdnct.age_band_id = '28-30m'
    AND abdnct.category_type_id = ct.id
    AND abdnct.is_active = true
);

